  1	import React, { useMemo } from 'react';
  2	import {
  3	  ChartsProvider,
  4	  ErrorBoundary,
  5	  generateChartsTheme,
  6	  getTheme,
  7	  PersesChartsTheme,
  8	  SnackbarProvider,
  9	  typography,
 10	} from '@perses-dev/components';
 11	import { ThemeProvider } from '@mui/material';
 12	import {
 13	  DataQueriesProvider,
 14	  dynamicImportPluginLoader,
 15	  PluginModuleResource,
 16	  PluginRegistry,
 17	  TimeRangeProvider,
 18	  useDataQueries,
 19	  usePluginBuiltinVariableDefinitions,
 20	} from '@perses-dev/plugin-system';
 21	import {
 22	  BuiltinVariableDefinition,
 23	  Definition,
 24	  DurationString,
 25	  DashboardResource,
 26	  UnknownSpec,
 27	} from '@perses-dev/core';
 28	import panelsResource from '@perses-dev/panels-plugin/plugin.json';
 29	import prometheusResource from '@perses-dev/prometheus-plugin/plugin.json';
 30	import {
 31	  DashboardProvider,
 32	  DatasourceStoreProvider,
 33	  VariableProviderWithQueryParams,
 34	} from '@perses-dev/dashboards';
 35	import { ChartThemeColor, getThemeColors } from '@patternfly/react-charts/victory';
 36	import ErrorAlert from '../shared/error';
 37	import { usePatternFlyTheme } from './hooks/usePatternflyTheme';
 38	import { CachedDatasourceAPI } from './perses/datasource-api';
 39	import { OcpDatasourceApi } from './datasource-api';
 40	import { PERSES_PROXY_BASE_PATH, useFetchPersesDashboard } from './perses-client';
 41	import { usePersesTimeRange } from './hooks/usePersesTimeRange';
 42	import { usePersesRefreshInterval } from './hooks/usePersesRefreshInterval';
 43	import { QueryParams } from '../../query-params';
 44	import { StringParam, useQueryParam } from 'use-query-params';
 45	import { useCookieWatcher } from './hooks/useCookieWatcher';
 46	import { useTranslation } from 'react-i18next';
 47	import { LoadingInline } from '../../console/console-shared/src/components/loading/LoadingInline';
 48	
 49	// Override eChart defaults with PatternFly colors.
 50	const patternflyBlue300 = '#2b9af3';
 51	const patternflyBlue400 = '#0066cc';
 52	const patternflyBlue500 = '#004080';
 53	const patternflyBlue600 = '#002952';
 54	const defaultPaletteColors = [patternflyBlue400, patternflyBlue500, patternflyBlue600];
 55	
 56	const patternflyChartsMultiUnorderedPalette = getThemeColors(
 57	  ChartThemeColor.multiUnordered,
 58	).chart.colorScale.flatMap((cssColor) => {
 59	  // colors are stored as 'var(--pf-chart-theme--multi-color-unordered--ColorScale--3400, #73c5c5)'
 60	  // need to extract the hex value, because fillStyle() of <canvas> does not support CSS vars
 61	  const match = cssColor.match(/#[a-fA-F0-9]+/);
 62	  return match ? [match[0]] : [];
 63	});
 64	
 65	// PluginRegistry configuration to allow access to
 66	// visualization panels/charts (@perses-dev/panels-plugin)
 67	// and data handlers for prometheus (@perses-dev/prometheus-plugin).
 68	const pluginLoader = dynamicImportPluginLoader([
 69	  {
 70	    resource: panelsResource as PluginModuleResource,
 71	    importPlugin: () => import('@perses-dev/panels-plugin'),
 72	  },
 73	  {
 74	    resource: prometheusResource as PluginModuleResource,
 75	    importPlugin: () => import('@perses-dev/prometheus-plugin'),
 76	  },
 77	]);
 78	
 79	interface PersesWrapperProps {
 80	  children?: React.ReactNode;
 81	  project: string;
 82	}
 83	
 84	export function PersesWrapper({ children, project }: PersesWrapperProps) {
 85	  const { theme } = usePatternFlyTheme();
 86	  const [dashboardName] = useQueryParam(QueryParams.Dashboard, StringParam);
 87	
 88	  const muiTheme = getTheme(theme, {
 89	    typography: {
 90	      ...typography,
 91	      fontFamily: 'var(--pf-t--global--font--family--body)',
 92	    },
 93	    shape: {
 94	      borderRadius: 0,
 95	    },
 96	  });
 97	
 98	  const chartsTheme: PersesChartsTheme = generateChartsTheme(muiTheme, {
 99	    echartsTheme: {
100	      color: patternflyChartsMultiUnorderedPalette,
101	    },
102	    thresholds: {
103	      defaultColor: patternflyBlue300,
104	      palette: defaultPaletteColors,
105	    },
106	  });
107	
108	  return (
109	    <ThemeProvider theme={muiTheme}>
110	      <ChartsProvider chartsTheme={chartsTheme}>
111	        <SnackbarProvider
112	          anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
113	          variant="default"
114	          content=""
115	        >
116	          <PluginRegistry pluginLoader={pluginLoader}>
117	            {!project ? (
118	              <>{children}</>
119	            ) : (
120	              <InnerWrapper project={project} dashboardName={dashboardName}>
121	                {children}
122	              </InnerWrapper>
123	            )}
124	          </PluginRegistry>
125	        </SnackbarProvider>
126	      </ChartsProvider>
127	    </ThemeProvider>
128	  );
129	}
130	
131	function InnerWrapper({ children, project, dashboardName }) {
132	  const { data } = usePluginBuiltinVariableDefinitions();
133	
134	  const { persesDashboard, persesDashboardLoading } = useFetchPersesDashboard(
135	    project,
136	    dashboardName,
137	  );
138	  const persesTimeRange = usePersesTimeRange();
139	  const persesRefrshInterval = usePersesRefreshInterval();
140	
141	  const builtinVariables = useMemo(() => {
142	    const result = [
143	      {
144	        kind: 'BuiltinVariable',
145	        spec: {
146	          name: '__dashboard',
147	          value: () => dashboardName,
148	          source: 'Dashboard',
149	          display: {
150	            name: '__dashboard',
151	            description: 'The name of the current dashboard',
152	            hidden: true,
153	          },
154	        },
155	      } as BuiltinVariableDefinition,
156	      {
157	        kind: 'BuiltinVariable',
158	        spec: {
159	          name: '__project',
160	          value: () => project,
161	          source: 'Dashboard',
162	          display: {
163	            name: '__project',
164	            description: 'The name of the current dashboard project',
165	            hidden: true,
166	          },
167	        },
168	      } as BuiltinVariableDefinition,
169	    ];
170	    if (data) {
171	      data.forEach((def: BuiltinVariableDefinition) => result.push(def));
172	    }
173	    return result;
174	  }, [data, project, dashboardName]);
175	
176	  if (persesDashboardLoading) {
177	    return null;
178	  }
179	
180	  let clearedDashboardResource: DashboardResource | undefined;
181	  if (Array.isArray(persesDashboard)) {
182	    if (persesDashboard.length === 0) {
183	      clearedDashboardResource = undefined;
184	    } else {
185	      clearedDashboardResource = persesDashboard[0];
186	    }
187	  } else {
188	    clearedDashboardResource = persesDashboard;
189	  }
190	
191	  return (
192	    <TimeRangeProvider refreshInterval={persesRefrshInterval} timeRange={persesTimeRange}>
193	      <VariableProviderWithQueryParams
194	        builtinVariableDefinitions={builtinVariables}
195	        initialVariableDefinitions={persesDashboard?.spec?.variables}
196	      >
197	        <PersesPrometheusDatasourceWrapper
198	          queries={[]}
199	          dashboardResource={clearedDashboardResource}
200	        >
201	          {clearedDashboardResource ? (
202	            <DashboardProvider
203	              initialState={{
204	                isEditMode: false,
205	                dashboardResource: clearedDashboardResource,
206	              }}
207	            >
208	              {children}
209	            </DashboardProvider>
210	          ) : (
211	            <>{children}</>
212	          )}
213	        </PersesPrometheusDatasourceWrapper>
214	      </VariableProviderWithQueryParams>
215	    </TimeRangeProvider>
216	  );
217	}
218	
219	interface PersesPrometheusDatasourceWrapperProps {
220	  queries: Definition<UnknownSpec>[];
221	  dashboardResource?: DashboardResource;
222	  duration?: DurationString;
223	  children?: React.ReactNode;
224	}
225	
226	export function PersesPrometheusDatasourceWrapper({
227	  queries,
228	  children,
229	  dashboardResource,
230	}: PersesPrometheusDatasourceWrapperProps) {
231	  const csrfToken = useCookieWatcher('csrf-token', { valueOnly: true });
232	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
233	  const datasourceApi = React.useMemo(() => {
234	    return new CachedDatasourceAPI(new OcpDatasourceApi(csrfToken, t, PERSES_PROXY_BASE_PATH));
235	  }, [csrfToken, t]);
236	
237	  return (
238	    <DatasourceStoreProvider dashboardResource={dashboardResource} datasourceApi={datasourceApi}>
239	      <DataQueriesProvider definitions={queries}>{children}</DataQueriesProvider>
240	    </DatasourceStoreProvider>
241	  );
242	}
243	
244	interface TimeSeriesPanelWrapperProps {
245	  noResults?: React.ReactNode;
246	  children?: React.ReactNode;
247	}
248	
249	/**
250	 * PrometheusQueryPanelWrapper intercepts the promql query status and displays PatternFly
251	 * native empty and loading states
252	 * instead of the Material UI empty and loading states used by Perses.
253	 */
254	export function TimeseriesQueryPanelWrapper({ noResults, children }: TimeSeriesPanelWrapperProps) {
255	  const { isFetching, isLoading, queryResults } = useDataQueries('TimeSeriesQuery');
256	
257	  if (isLoading || isFetching) {
258	    return <LoadingInline />;
259	  }
260	
261	  const queryError = queryResults.find((d) => d.error);
262	  if (queryError) {
263	    return <ErrorAlert error={queryError.error as Error} />;
264	  }
265	
266	  const dataFound = queryResults.some(
267	    (timeSeriesData) =>
268	      (timeSeriesData.data?.series ?? []).length > 0 || timeSeriesData.data?.series,
269	  );
270	  if (!dataFound && noResults) {
271	    return <>{noResults}</>;
272	  }
273	
274	  return (
275	    <ErrorBoundary FallbackComponent={ErrorAlert} resetKeys={[]}>
276	      {children}
277	    </ErrorBoundary>
278	  );
279	}

